1251	const runRepositoryChatTurn = async <T>(
1252	  runPromise: Promise<T>,
1253	  abortController: AbortController,
1254	  options: {
1255	    timeoutMs: number;
1256	    setTimeoutFn: (callback: () => void, ms: number) => RepositoryChatTimeoutHandle;
1257	    clearTimeoutFn: (handle: RepositoryChatTimeoutHandle) => void;
1258	  }
1259	): Promise<T> => {
1260	  if (!Number.isFinite(options.timeoutMs) || options.timeoutMs <= 0) {
1261	    return runPromise;
1262	  }
1263	
1264	  let timeoutHandle: RepositoryChatTimeoutHandle | null = null;
1265	  const timeoutPromise = new Promise<never>((_resolve, reject) => {
1266	    timeoutHandle = options.setTimeoutFn(() => {
1267	      const timeoutDescription =
1268	        options.timeoutMs >= 1000 ? `${Math.round(options.timeoutMs / 1000)} seconds` : `${options.timeoutMs}ms`;
1269	      abortController.abort();
1270	      reject(new Error(`Repository chat timed out after ${timeoutDescription}.`));
1271	    }, options.timeoutMs);
1272	  });
1273	
1274	  try {
1275	    return await Promise.race([runPromise, timeoutPromise]);
1276	  } finally {
1277	    if (timeoutHandle) {
1278	      options.clearTimeoutFn(timeoutHandle);
1279	    }
1280	    runPromise.catch(() => undefined);
1281	  }
1282	};
